<section class="admin-page-head"><div><a class="back-link" href="<?= url('admin/products') ?>"><i data-lucide="arrow-left"></i>Products</a><span class="eyebrow"><?= $product?'Catalog update':'New catalog item' ?></span><h1><?= e($title) ?></h1><p>Keep the essentials visible. Advanced fields can be added later.</p></div></section><form method="post" enctype="multipart/form-data" class="admin-form-layout"><?= csrf_field() ?><div class="admin-panel form-panel"><div class="form-section"><span class="step-label">Product basics</span><div class="form-grid"><label>Product name<input name="name" value="<?= e($product['name']??'') ?>" required></label><label>Brand<input name="brand" value="<?= e($product['brand']??'') ?>"></label><label>Category<select name="category_id"><?php foreach($categories as $category): ?><option value="<?= (int)$category['id'] ?>" <?= ($product['category_id']??null)==$category['id']?'selected':'' ?>><?= e($category['name']) ?></option><?php endforeach; ?></select></label><label>Type<select name="strain_type"><option value="">Not specified</option><?php foreach(['Sativa','Hybrid','Indica'] as $type): ?><option <?= ($product['strain_type']??'')===$type?'selected':'' ?>><?= $type ?></option><?php endforeach; ?></select></label><label class="full">Description<textarea name="description" rows="4"><?= e($product['description']??'') ?></textarea></label></div></div><div class="form-section"><span class="step-label">Price and option</span><div class="form-grid"><label>Option label<input name="variant_label" value="<?= e($variant['label']??'Single') ?>" placeholder="3.5g or 5 pack" required></label><label>Potency / package note<input name="potency" value="<?= e($product['potency']??'') ?>" placeholder="500mg or 2g"></label><label>Regular price<input type="number" name="price" step="0.01" min="0.01" value="<?= isset($variant)?number_format($variant['price_cents']/100,2,'.',''):'' ?>" required></label><label>Sale price<input type="number" name="sale_price" step="0.01" min="0" value="<?= !empty($variant['sale_price_cents'])?number_format($variant['sale_price_cents']/100,2,'.',''):'' ?>"></label><label class="full">Flavors or options<textarea name="flavors" rows="3" placeholder="Separate options with commas"><?= e($variant['flavors']??'') ?></textarea></label></div></div><div class="form-section"><span class="step-label">Photo and visibility</span><div class="form-grid"><label class="full file-label"><span>Product photo</span><input type="file" name="image" accept="image/jpeg,image/png,image/webp"><small>JPG, PNG or WebP, up to 8 MB.</small></label><label>Status<select name="status"><?php foreach(['draft','active','sold_out','archived'] as $status): ?><option value="<?= $status ?>" <?= ($product['status']??'active')===$status?'selected':'' ?>><?= e(ucwords(str_replace('_',' ',$status))) ?></option><?php endforeach; ?></select></label><label>Stock<select name="stock_status"><?php foreach(['in_stock','low_stock','sold_out'] as $status): ?><option value="<?= $status ?>" <?= ($variant['stock_status']??'in_stock')===$status?'selected':'' ?>><?= e(ucwords(str_replace('_',' ',$status))) ?></option><?php endforeach; ?></select></label><label class="check-row full"><input type="checkbox" name="featured" value="1" <?= !empty($product['featured'])?'checked':'' ?>><span>Feature this product on the homepage</span></label></div></div></div><aside class="admin-panel form-actions"><h2>Publish</h2><p>Changes appear in the menu as soon as they are saved.</p><?php if(!empty($product['image_path'])): ?><img class="form-preview" src="<?= url($product['image_path']) ?>" alt="Current product image"><?php endif; ?><button class="button button-primary button-wide" type="submit">Save product<i data-lucide="save"></i></button><a class="button button-secondary button-wide" href="<?= url('admin/products') ?>">Cancel</a></aside></form>

